#include <stdio.h>
#include <stdint.h>

int64_t fastPower(int64_t base, int exponent) {
    int64_t result = 1;
    while (exponent > 0) {
        if (exponent & 1) result *= base;
        base *= base;
        exponent >>= 1;
    }
    return result;
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int64_t base;
        int exponent;
        if (scanf("%lld %d", &base, &exponent) != 2) break;
        int64_t ans = fastPower(base, exponent);
        printf("%lld\n", ans);
    }
    return 0;
}

