code.Java:
import java.io.*;
import java.util.*;

public class Main {
    private static long fastPower(long base, int exponent) {
        long result = 1L;
        while (exponent > 0) {
            if ((exponent & 1) == 1) result *= base;
            base *= base;
            exponent >>= 1;
        }
        return result;
    }
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        String line = br.readLine();
        if (line == null || line.isEmpty()) return;
        int T = Integer.parseInt(line.trim());
        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < T; i++) {
            StringTokenizer st = new StringTokenizer(br.readLine());
            long base = Long.parseLong(st.nextToken());
            int exponent = Integer.parseInt(st.nextToken());
            sb.append(fastPower(base, exponent)).append('\n');
        }
        System.out.print(sb.toString());
    }
}

code.Python3:
#!/usr/bin/env python3
import sys

def fast_power(base: int, exponent: int) -> int:
    result = 1
    while exponent:
        if exponent & 1:
            result *= base
        base *= base
        exponent >>= 1
    return result

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    t = int(data[0])
    idx = 1
    out = []
    for _ in range(t):
        base = int(data[idx]); exponent = int(data[idx+1]); idx += 2
        out.append(str(fast_power(base, exponent)))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    main()

